patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index e816e943380f5..c419c6117ef77 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -2386,7 +2386,9 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Value *V,
           return PoisonValue::get(VTy);

         // Only need nan propagation.
-        // Note: Dropping snan quieting.
+        if ((DemandedMask & ~fcNan) == fcNone)
+          return ConstantFP::getQNaN(VTy);
+
         return CI->getArgOperand(0);
       }

@@ -2471,7 +2473,9 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Value *V,
       }

       Known = KnownFPClass::exp(KnownSrc);
-      break;
+
+      FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
+      return getFPClassConstant(VTy, ValidResults, /*IsCanonicalizing=*/true);
     }
     case Intrinsic::log:
     case Intrinsic::log2:

